@keyframes shimmer {
  0% {
    background-position: -200% 0;
  }
  100% {
    background-position: 200% 0;
  }
}

/* Shimmer Effect Class */
.shimmer {
  position: relative;
  overflow: hidden;
  background: linear-gradient(
    90deg,
    var(--shimmer-bg-from, #f0f0f0) 0%,
    var(--shimmer-bg-mid, #e0e0e0) 50%,
    var(--shimmer-bg-to, #f0f0f0) 100%
  );
  background-size: 200% 100%;
  animation: shimmer var(--shimmer-duration, 1.5s) infinite linear;
}

/* Plain Skeleton (No Animation) */
.shimmer--plain {
  animation: none;
  background: var(--shimmer-bg-from, #f0f0f0);
}

/* Shape Variants */
.shimmer--rect {
  border-radius: 0;
}

.shimmer--circle {
  border-radius: 50%;
}

.shimmer--rounded {
  border-radius: 4px;
}

/* Utility Classes */
.shimmer--wide {
  --shimmer-duration: 2.5s;
}

.shimmer--fast {
  --shimmer-duration: 0.5s;
}

/* Default Variables */
:root {
  --shimmer-bg-from: #f0f0f0;
  --shimmer-bg-mid: #e0e0e0;
  --shimmer-bg-to: #f0f0f0;
  --shimmer-duration: 1.5s;
}
