import './SuspenseBoundary.css';

export interface SuspenseBoundaryProps {
  /** Component to render while loading */
  fallback?: React.ReactNode;
  /** Child component to load lazily */
  children: React.ReactNode | (() => React.LazyExoticComponent<React.ElementType<any>>);
}

/**
 * SuspenseBoundary Component
 * 
 * Wraps lazily-loaded components to show skeleton placeholders during loading
 * and displays fallback content if the child throws an error.
 */
export const SuspenseBoundary: React.FC<SuspenseBoundaryProps> = ({
  fallback = <div className="suspense-boundary__fallback">Loading...</div>,
  children,
}) => {
  return (
    <Suspense fallback={fallback}>
      {children}
    </Suspense>
  );
};

export default SuspenseBoundary;
