          animation: variant === 'shimmer' ? 'shimmer 1.5s infinite linear' : 'none',
        }}
      >
        {customShape}
      </div>
    );
  }

  // Handle predefined shape variants
  const borderRadius = skeletonStyles[shape as SkeletonShape].borderRadius;

  return (
    <div
      style={{
        width,
        height,
        backgroundImage: variant === 'shimmer' ? 'linear-gradient(90deg, #f0f0f0 0%, #e0e0e0 50%, #f0f0f0 100%)' : 'var(--shimmer-bg-from, #f0f0f0)',
