import { useSyncExternalStore } from 'react-dom';

/**
 * useSuspense Hook
 * 
 * A custom hook for managing suspense loading states with React Suspense integration.
 * 
 * @template T - The type of the loaded data
 * 
 * @param {() => Promise<T>} loadAsync - Async function that returns a Promise with the data
 * @param {React.ReactNode} [fallback] - Optional fallback content to render while loading
 * 
 * @returns {{
 *   loading: boolean,
 *   data: T | null,
 *   error: Error | null,
 *   onLoad: (callback: () => void) => void,
 * }}
 * 
 * @example
 * ```tsx
 * const { loading, data, error, onLoad } = useSuspense(
 *   async () => {
 *     // Fetch data
 *     const res = await fetch('/api/data');
 *     return res.json();
 *   },
 *   <Skeleton /> // Optional fallback
 * );
 * ```
 */

export interface UseSuspenseReturn<T> {
  /** Whether data is currently loading */
  loading: boolean;
  /** The loaded data (null while loading or on error) */
  data: T | null;
  /** Error from the async operation (null on success) */
  error: Error | null;
  /** Callback to trigger the data load */
  onLoad: (callback?: () => void) => void;
}

export type UseSuspenseLoadAsync<T> = () => Promise<T>;

export type UseSuspenseFallback<T = unknown> = React.ReactNode;

export type UseSuspenseOptions<T> = {
  /** Optional fallback content */
  fallback?: UseSuspenseFallback<T>;
  /** Optional key for forcing a reload */
  key?: string;
};

export const useSuspense = <T = unknown>(
  loadAsync: UseSuspenseLoadAsync<T>,
  options: UseSuspenseOptions<T> = {}
): UseSuspenseReturn<T> => {
  const { fallback, key = '' } = options;
  const loadKey = useRef<string>(key);

  // Use a ref to track the current load key (for external changes)
  const loadKeyRef = useRef<string>(loadKey.current);

  // Create a cleanup function to reset the key when options change
  useEffect(() => {
    loadKey.current = key;
    loadKeyRef.current = key;
    return () => {
      loadKey.current = '';
      loadKeyRef.current = '';
    };
  }, [key]);

  const [state, setState] = useState<{
    loading: boolean;
    data: T | null;
    error: Error | null;
  }>({
    loading: true,
    data: null,
    error: null,
  });

  // Reset to loading state when the key changes
  useEffect(() => {
    if (loadKey.current !== loadKeyRef.current) {
      setState((prev) => ({ ...prev, loading: true, data: null, error: null }));
    }
  }, [loadKey.current]);

  /**
   * Triggers the data load
   * 
   * @param {() => void} [callback] - Optional callback after load completes
   */
  const onLoad = useCallback((callback?: () => void) => {
    setState((prev) => ({ ...prev, loading: true, data: null, error: null }));

    loadAsync()
      .then((data) => {
        setState((prev) => ({
          ...prev,
          loading: false,
          data,
          error: null,
        }));
        callback?.();
      })
      .catch((error) => {
        setState((prev) => ({
          ...prev,
          loading: false,
          data: null,
          error,
        }));
        callback?.();
      });
  }, [loadAsync]);

  return {
    loading: state.loading,
    data: state.data,
    error: state.error,
    onLoad,
  };
};

export default useSuspense;
