/* Skeleton base styles with CSS variables */
.skeleton {
  position: relative;
  overflow: hidden;
  background: var(--skeleton-bg, #f0f0f0);
  border-radius: var(--skeleton-border-radius, 4px);
}

/* Shimmer Effect Class */
.skeleton--shimmer {
  background-image: linear-gradient(
    90deg,
    var(--skeleton-bg-from, #f0f0f0) 0%,
    var(--skeleton-bg-mid, #e0e0e0) 50%,
    var(--skeleton-bg-to, #f0f0f0) 100%
  );
  background-size: 200% 100%;
  animation: shimmer var(--skeleton-duration, 1.5s) infinite linear;
}

/* Plain Skeleton (No Animation) */
.skeleton--plain {
  background: var(--skeleton-bg-plain, #f0f0f0);
  background-image: none;
  animation: none;
}

/* Shape Variants */
.skeleton--rect {
  --skeleton-border-radius: 0;
}

.skeleton--circle {
  --skeleton-border-radius: 50%;
}

.skeleton--rounded {
  --skeleton-border-radius: 4px;
}

/* Utility Classes for Duration */
.skeleton--wide {
  --skeleton-duration: 2.5s;
}

.skeleton--fast {
  --skeleton-duration: 0.5s;
}

/* Default Variables */
:root {
  --skeleton-bg-from: #f0f0f0;
  --skeleton-bg-mid: #e0e0e0;
  --skeleton-bg-to: #f0f0f0;
  --skeleton-bg-plain: #f0f0f0;
