import { SuspenseBoundary } from './SuspenseBoundary';

// Mock a lazy component that takes time to load
const mockLazyComponent = () => {
  return React.lazy(() => {
    return new Promise<any>((resolve) => {
      setTimeout(() => {
        resolve({
          default: () => <div data-testid="lazy-content">Loaded!</div>,
        });
      }, 100);
    });
  });
};

describe('SuspenseBoundary Component', () => {
  it('renders fallback content during loading', async () => {
    const LazyComponent = mockLazyComponent();

    render(
      <SuspenseBoundary fallback={<div data-testid="custom-fallback">Custom Fallback</div>}>
        <LazyComponent />
      </SuspenseBoundary>
    );

    // Should show custom fallback immediately
    expect(screen.getByTestId('custom-fallback')).toBeInTheDocument();

    // After component loads, fallback should disappear
    await act(async () => {
      await new Promise((resolve) => setTimeout(resolve, 150));
    });

    expect(screen.getByTestId('lazy-content')).toBeInTheDocument();
    expect(screen.getByTestId('custom-fallback')).not.toBeInTheDocument();
  });

  it('renders default fallback when none provided', async () => {
    const LazyComponent = mockLazyComponent();

    render(
      <SuspenseBoundary>
        <LazyComponent />
      </SuspenseBoundary>
    );

    // Should show default "Loading..." fallback
    expect(screen.getByText('Loading...')).toBeInTheDocument();

    // After component loads, fallback should disappear
    await act(async () => {
      await new Promise((resolve) => setTimeout(resolve, 150));
    });

    expect(screen.getByTestId('lazy-content')).toBeInTheDocument();
  });

  it('renders normal content after data loads', async () => {
    const LazyComponent = mockLazyComponent();

    const { container } = render(
      <SuspenseBoundary>
        <LazyComponent />
      </SuspenseBoundary>
    );

    // Initially shows fallback
    expect(screen.getByText('Loading...')).toBeInTheDocument();

    // Wait for component to load
    await act(async () => {
      await new Promise((resolve) => setTimeout(resolve, 150));
    });

    // Should now show content
    expect(screen.getByTestId('lazy-content')).toBeInTheDocument();
    expect(screen.getByText('Loaded!')).toBeInTheDocument();
  });

  it('renders custom fallback with Skeleton during loading', async () => {
    const LazyComponent = mockLazyComponent();

    const { Skeleton } = await import('./Skeleton');

    render(
      <SuspenseBoundary
        fallback={
          <div data-testid="fallback">
            <Skeleton shape="rect" />
          </div>
        }
      >
        <LazyComponent />
      </SuspenseBoundary>
    );

    expect(screen.getByTestId('fallback')).toBeInTheDocument();

    await act(async () => {
      await new Promise((resolve) => setTimeout(resolve, 150));
    });

    expect(screen.getByTestId('lazy-content')).toBeInTheDocument();
  });

  it('handles errors in lazy component by re-throwing', async () => {
    const errorLazyComponent = () => {
      return React.lazy(() => {
        return new Promise<any>((_, reject) => {
          setTimeout(() => {
            reject(new Error('Component failed to load'));
          }, 100);
        });
      });
    };

    render(
      <SuspenseBoundary fallback={<div data-testid="error-fallback">Error Fallback</div>}>
        <errorLazyComponent />
      </SuspenseBoundary>
    );

    // Should show error fallback
    expect(screen.getByTestId('error-fallback')).toBeInTheDocument();
  });
});
