  width = '100%',
  height = '1rem',
  variant = 'shimmer',
  className,
}) => {
  // Validate shape prop
  if (!skeletonStyles[shape as SkeletonShape]) {
    console.error(`Invalid shape: ${shape}. Available shapes: rect, circle, rounded`);
  }

  const borderRadius = skeletonStyles[shape].borderRadius;

  // Build class name with shape and variant modifiers
  const baseClasses = [
    'skeleton',
    `skeleton--${shape}`,        // rect, circle, rounded
    `skeleton--${variant}`,      // shimmer, plain
  ].join(' ');

  return (
    <div
      style={{
        width,
        height,
        borderRadius,
      }}
      className={baseClasses + (className ? ` ${className}` : '')}
    />
  );
};
