    'skeleton',
    `skeleton--${shape}`,        // rect, circle, rounded
    `skeleton--${variant}`,      // shimmer, plain
  ].join(' ');

  return (
    <div
      style={{
        width,
        height,
        borderRadius,
      }}
      className={baseClasses + (className ? ` ${className}` : '')}
    />
  );
};
